def _pick_emoji(name, options):
    key = name.lower()
    for keywords, emoji in options:
        if any(keyword in key for keyword in keywords):
            return emoji

    return None


def _build_item_emoji(name, item_type, rank):
    weapon_options = [
        (("fang", "blade", "sword", "saber", "cleaver", "dagger", "knife", "hook", "reaper", "edge", "scythe", "axe", "spear", "rapier"), "🗡️"),
        (("storm", "thunder", "gale", "wind", "tempest"), "⚡"),
        (("ember", "cinder", "fire", "flame", "volcanic", "sun", "forge", "melt"), "🔥"),
        (("moon", "frost", "glacier", "ice", "winter", "snow", "mist"), "🌙"),
        (("star", "sky", "celestial", "aurora", "eclipse", "halo", "comet"), "🌠"),
        (("dragon", "void", "abyss", "rift", "cataclysm"), "🐉"),
        (("root", "branch", "wood", "bamboo", "stick", "cane", "rod", "oak", "pine", "willow", "ash", "maple"), "🌿"),
        (("stone", "iron", "steel", "bronze", "copper", "granite", "shale", "rock", "morrow", "warden", "breaker"), "🪨"),
        (("whisper", "silk", "velvet", "hush", "silent", "shadow", "mild", "plain", "soft"), "🪶"),
    ]

    armor_options = [
        (("scale", "mail", "plate", "guard", "vest", "armor", "cuirass", "chestguard", "shield", "mantle"), "🛡️"),
        (("cloak", "robe", "wrap", "cape", "mantle", "shirt", "coat", "vest", "mail", "guard"), "🥋"),
        (("frost", "ice", "glacier", "winter", "mist", "snow"), "❄️"),
        (("ember", "blaze", "flame", "fire", "volcanic", "storm"), "🔥"),
        (("star", "moon", "celestial", "aurora", "halo", "eclipse"), "🌙"),
        (("stone", "granite", "iron", "steel", "bronze", "copper", "shale", "battered", "dented", "morrow", "warden", "breaker"), "🪨"),
        (("root", "branch", "wood", "reed", "willow", "oak", "pine", "moss", "ash", "tin", "lead"), "🌿"),
        (("void", "abyss", "shadow", "night", "raven", "dusk"), "🌌"),
    ]

    fallback_pool = {
        "weapon": ["⚔️", "🗡️", "�", "�", "�"],
        "armor": ["🛡️", "�", "�", "�", "🪨"],
    }

    themed_options = weapon_options if item_type == "weapon" else armor_options
    emoji = _pick_emoji(name, themed_options)
    if emoji:
        accent_pool = {
            "weapon": ["✨", "💫", "⚡", "🔥", "🌠", "🌀"],
            "armor": ["✨", "💫", "❄️", "🪷", "🌙", "🫧"],
        }
        accent = accent_pool.get(item_type, ["✨"])[sum(ord(char) for char in f"{name}{rank}") % len(accent_pool.get(item_type, ["✨"]))]
        return f"{emoji}{accent}"

    pool = fallback_pool.get(item_type, ["✨"])
    accent_pool = {
        "weapon": ["✨", "💫", "⚡", "🔥", "🌠", "🌀"],
        "armor": ["✨", "💫", "❄️", "🪷", "🌙", "🫧"],
    }
    base = pool[sum(ord(char) for char in f"{name}{rank}{item_type}") % len(pool)]
    accent = accent_pool.get(item_type, ["✨"])[sum(ord(char) for char in f"{rank}{name}") % len(accent_pool.get(item_type, ["✨"]))]
    return f"{base}{accent}"


_starter_items_source = STARTER_ITEMS
STARTER_ITEMS = {
    item_type: [dict(item, type=item_type, emoji=_build_item_emoji(item["name"], item_type, item["rank"])) for item in items]
    for item_type, items in _starter_items_source.items()
}

STARTER_ITEM_RANK_CHANCES = {
    "A": 0,
    "A-": 0.5,
    "B+": 1,
    "B": 2,
    "B-": 4,
    "C+": 7,
    "C": 12,
    "C-": 15,
    "D+": 18,
    "D": 18,
    "D-": 12,
    "E": 8,
    "F": 2.5,
}


def get_item_pool(item_type):
    return STARTER_ITEMS.get(item_type, [])


def get_rank_chances():
    return STARTER_ITEM_RANK_CHANCES
